function getGatewayWalletAddress(chain) {
    if (!isGatewayV1Supported(chain)) {
        throw new KitError({
            ...InputError.INVALID_CHAIN,
            recoverability: 'FATAL',
            message: 'Gateway Wallet address not found: chain does not have Gateway v1 contracts configured.'
        });
    }
    return chain.gateway.contracts.v1.wallet;
}
function getGatewayMinterAddress(chain) {
    if (!isGatewayV1Supported(chain)) {
        throw new KitError({
            ...InputError.INVALID_CHAIN,
            recoverability: 'FATAL',
            message: 'Gateway Minter address not found: chain does not have Gateway v1 contracts configured.'
        });
    }
    return chain.gateway.contracts.v1.minter;
}
function resolveSignatureArgs(commonArgs, fields, functionName) {
    if (fields.signature !== undefined) {
        return [
            ...commonArgs,
            fields.signature
        ];
    }
    if (fields.v === undefined || fields.r === undefined || fields.s === undefined) {
        throw new KitError({
            ...InputError.VALIDATION_FAILED,
            recoverability: 'FATAL',
            message: `${functionName} requires either signature bytes or v, r, s`
        });
    }
    return [
        ...commonArgs,
        fields.v,
        fields.r,
        fields.s
    ];
}
