// ============================================================================
// Special: signBurnIntents (local signing, not a contract call)
// ============================================================================
/**
 * Create a bound `gateway.v1.signBurnIntents` read action for EVM.
 *
 * @remarks
 * `signBurnIntents` is an off-chain EIP-712 signing operation rather than a
 * contract call, so it cannot reuse the generic `ctx.read` / `ctx.write`
 * surface. Instead, the ecosystem adapter injects its `signTypedData`
 * primitive via {@link BindGatewaySignBurnIntentsOptions} and the binding
 * delegates to it. This mirrors the legacy `@core/adapter-evm` path, which
 * calls `adapter.signTypedData` directly.
 *
 * When `options.signTypedData` is omitted the binding falls back to the
 * legacy no-op sentinel (`{ signature: '0x' }`) to preserve backward-compat
 * with existing `createEVMActions(adapter, { getNativeBalance })` callers
 * that have not yet wired in the signing surface.
 *
 * @param adapter - The EVM adapter the action will be bound to.
 * @param options - Optional injectors; pass `signTypedData` to enable
 *   real signatures (otherwise the binding stays a no-op).
 * @returns A bound `gateway.v1.signBurnIntents` read action.
 */ function bindGatewaySignBurnIntents(adapter, options = {}) {
    const { signTypedData, readBytecode } = options;
    if (signTypedData === undefined) {
        return gatewayV1SignBurnIntents.bind({
            adapter,
            execute: noopWith({
                signature: '0x'
            })
        });
    }
    return gatewayV1SignBurnIntents.bind({
        adapter,
        execute: async (input, ctx)=>{
            assertEVMChain(ctx.chain);
            // Gateway verifies burn-intent signatures with plain ecrecover and
            // does not fall back to ERC-1271. An SCA signer would silently
            // produce an unverifiable signature and Circle Wallets' KMS rejects
            // the typed data up front with an opaque `<nil>/<nil>` error. When
            // the ecosystem adapter has wired in `readBytecode`, short-circuit
            // with the delegate-pattern recipe before signing. Mirror of the
            // legacy fix landed in #954 (DEVX-2774). When `readBytecode` is
            // omitted (older wirings, mocks, …) the pre-check is skipped — the
            // adapter still produces the same signature it did before this fix.
            const signerAddress = typeof ctx.address === 'string' ? ctx.address : undefined;
            if (readBytecode !== undefined && signerAddress !== undefined && signerAddress.length > 0) {
                await assertSignerIsEoa(readBytecode, signerAddress, ctx.chain);
            }
            const signature = await signTypedData(input.typedData, ctx);
            return {
                signature
            };
        }
    });
}

/**
 * EIP-7528 native token sentinel address.
 *
 * @remarks
 * Used by the stablecoin-service to flag native-currency swaps. When
 * `tokenInAddress` matches this sentinel, `inputAmount` is attached to the
 * transaction as `value` and no permit pull happens.
 */ const NATIVE_TOKEN_ADDRESS = '0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE';
/**
 * Property-based type guard that narrows to EVM swap inputs.
 *
 * @remarks
 * The `swap.execute` action accepts a union of EVM and Solana inputs; each
 * ecosystem binding narrows at runtime. The EVM shape is identified by the
 * presence of the required `executeParams` / `signature` / `tokenInAddress`
 * properties; checking those is enough to rule out the Solana variant.
 */ function isEVMSwapInput(input) {
    return 'executeParams' in input && 'tokenInputs' in input && 'signature' in input && 'inputAmount' in input && 'tokenInAddress' in input;
}
/**
 * Create a bound `swap.execute` write action for EVM.
 *
 * @remarks
 * Resolves the Adapter Contract address from `chain.kitContracts.adapter`
 * and dispatches a single call to `execute(executeParams, tokenInputs,
 * signature)`. Throws a FATAL `INPUT` error if the chain is not EVM, lacks
 * an Adapter Contract configuration, or receives a non-EVM swap payload.
 */ function bindSwapExecute(adapter) {
    return swapExecute.bind({
        adapter,
        build: (input, ctx)=>{
            assertEVMChain(ctx.chain);
            if (!isEVMSwapInput(input)) {
                throw new KitError({
                    ...InputError.VALIDATION_FAILED,
                    recoverability: 'FATAL',
                    message: 'swap.execute on EVM requires EVM swap parameters ' + '(executeParams, tokenInputs, signature, inputAmount, tokenInAddress).'
                });
            }
            if (!hasCustomContractSupport(ctx.chain, 'adapter')) {
                throw new KitError({
                    ...InputError.UNSUPPORTED_ROUTE,
                    recoverability: 'FATAL',
                    message: `Chain "${ctx.chain.name}" does not have an Adapter Contract ` + 'configured. Swap execution requires kitContracts.adapter to be set.'
                });
            }
            const adapterAddress = hexAddress.parse(ctx.chain.kitContracts?.adapter);
            const isNativeSwap = input.tokenInAddress.toLowerCase() === NATIVE_TOKEN_ADDRESS.toLowerCase();
            // Sum the native value required by each instruction. Some bridges (e.g.
            // Stargate V2) charge a LayerZero messaging fee in native currency
            // regardless of the input token, so it must be forwarded even for ERC-20
            // swaps — not just native-input swaps.
            const instructionValueSum = input.executeParams.instructions.reduce((acc, instruction)=>acc + instruction.value, 0n);
            // For native-input swaps the service usually encodes the native swap
            // value in the instruction list itself. Use the larger of the two so we
            // neither double-count same-chain native swaps nor regress the older
            // fallback where instruction values were absent.
            let totalValue = instructionValueSum;
            if (isNativeSwap && input.inputAmount > totalValue) {
                totalValue = input.inputAmount;
            }
            // Native funding (swap value and/or bridge messaging fee) is pulled from
            // the caller at runtime — it is NOT covered by the EIP-712 signature, so
            // the Adapter can safely take a larger value than signed. Any over-fund
            // (wei dust or a bridge refund) must therefore be sweepable back to the
            // sender via a NATIVE_TOKEN residual recipient, otherwise it is stranded
            // in the Adapter Contract.
            if (totalValue > 0n) {
                const hasNativeResidualRecipient = input.executeParams.tokens.some(({ token, beneficiary })=>token.toLowerCase() === NATIVE_TOKEN_ADDRESS.toLowerCase() && beneficiary.toLowerCase() === ctx.address.toLowerCase());
                if (!hasNativeResidualRecipient) {
                    throw new KitError({
                        ...InputError.VALIDATION_FAILED,
                        recoverability: 'FATAL',
                        message: 'Native-funded swaps must include a NATIVE_TOKEN residual ' + 'recipient for the sender in executeParams.tokens.'
                    });
                }
            }
            ctx.write({
                address: adapterAddress,
                abi: adapterContractAbi,
                functionName: 'execute',
                args: [
                    input.executeParams,
                    input.tokenInputs,
                    input.signature
                ],
                ...totalValue > 0n && {
                    value: totalValue
                }
            });
        }
    });
}

