/**
 * Build callback shared by all three earn action keys.
 *
 * @remarks
 * Validates the chain, resolves the Adapter Contract address, and queues the
 * `execute(executeParams, tokenInputs, signature)` write via `ctx.write`.
 * No network I/O is performed — only calldata construction.
 */ function buildEarnExecute(input, ctx) {
    assertEVMChain(ctx.chain);
    if (!hasCustomContractSupport(ctx.chain, 'adapter')) {
        throw new KitError({
            ...InputError.UNSUPPORTED_ROUTE,
            recoverability: 'FATAL',
            message: `Chain "${ctx.chain.name}" does not have an Adapter Contract ` + 'configured. Earn execution requires kitContracts.adapter to be set.'
        });
    }
    const adapterAddress = hexAddress.parse(ctx.chain.kitContracts?.adapter);
    ctx.write({
        address: adapterAddress,
        abi: adapterContractAbi,
        functionName: 'execute',
        args: [
            input.executeParams,
            input.tokenInputs,
            input.signature
        ]
    });
}
