/**
 * Creates an address resolver function for the adapter context.
 *
 * @param options - Configuration options
 * @returns An async function that resolves the current address for a chain
 *
 * @remarks
 * For user-controlled adapters, this resolves the address from the wallet.
 * For developer-controlled adapters, this throws an error since addresses
 * must be provided explicitly in the operation context.
 *
 * @example
 * ```typescript
 * const getAddress = createGetAddress({
 *   isDeveloperControlled: false,
 *   getWalletClient,
 * })
 *
 * const address = await getAddress(Ethereum)
 * ```
 */ function createGetAddress(options) {
    const { isDeveloperControlled, getWalletClient, address: boundAddress } = options;
    return async function getAddress(chain) {
        if (isDeveloperControlled) {
            throw new KitError({
                ...InputError.VALIDATION_FAILED,
                recoverability: 'FATAL',
                message: 'Cannot call getAddress() on developer-controlled adapters. ' + 'Address must be provided explicitly in the operation context.'
            });
        }
        if (chain.type !== 'evm') {
            throw new KitError({
                ...InputError.INVALID_CHAIN,
                recoverability: 'FATAL',
                message: `ViemAdapter only supports EVM chains. Received: ${chain.type} (${chain.name})`
            });
        }
        // A bound address makes a read-only or signing-strategy adapter (no wallet
        // client) expressible: return it without consulting a wallet.
        if (boundAddress !== undefined) {
            return boundAddress;
        }
        const walletClient = await getWalletClient(chain);
        const address = walletClient.account?.address ?? (await walletClient.getAddresses())[0];
        if (address === undefined) {
            throw new KitError({
                ...RpcError.ENDPOINT_ERROR,
                recoverability: 'FATAL',
                message: 'No addresses available in wallet. Please connect a wallet to continue.'
            });
        }
        return address;
    };
}

